const initFilamentTree = () => {
	const containers = document.querySelectorAll('#studio15-tree .studio15-tree');

	containers.forEach((container) => {
		if (container.sortableInstance) {
			return;
		}

		container.sortableInstance = Sortable.create(container, {
			group: 'tree-nested',
			animation: 150,
			fallbackOnBody: true,
			swapThreshold: 1,
			handle: '.tree-row-draggable',
			onEnd: (evt) => {
				const data = {
					id: evt.item.dataset.id,
					ancestor: evt.from.dataset.id,
					parent: evt.to.dataset.id,
					from: evt.oldIndex,
					to: evt.newIndex,
				};

				if (data.parent !== data.ancestor || data.from !== data.to) {
					window.Livewire.dispatch('filament-tree-moved', data);
				}
			},
		});
	});
};

let filamentTreeCommitHookRegistered = false;

const bootFilamentTree = () => {
	initFilamentTree();

	if (!filamentTreeCommitHookRegistered && window.Livewire && typeof window.Livewire.hook === 'function') {
		window.Livewire.hook('morphed', () => {
			initFilamentTree();
		});

		filamentTreeCommitHookRegistered = true;
	}
};

document.addEventListener('livewire:init', bootFilamentTree);
document.addEventListener('livewire:initialized', bootFilamentTree);
document.addEventListener('livewire:navigated', bootFilamentTree);
document.addEventListener('DOMContentLoaded', bootFilamentTree, { once: true });

